function renderGhostCards(host,n){n=n||8;var rows='';for(var j=0;j<4;j++){rows+='<div class="cr-row"><span class="gh gh-line" style="width:34%"></span><span class="gh gh-line" style="width:22%"></span></div>';}var card='<div class="cr-card cr-ghost"><div class="cr-img gh"></div><div class="cr-body"><div class="gh gh-line" style="width:75%;height:13px"></div><div class="cr-rows" style="margin-top:12px">'+rows+'</div></div></div>';var h='';for(var i=0;i<n;i++)h+=card;host.innerHTML=h;}
function cdSmooth(y,w){w=w||3;var o=[];for(var i=0;i<y.length;i++){var a=Math.max(0,i-(w>>1)),b=Math.min(y.length,i+(w>>1)+1),s=0;for(var j=a;j<b;j++)s+=y[j];o.push(s/(b-a));}return o;}
function cdMean(y){if(!y.length)return 0;for(var i=0,s=0;i<y.length;i++)s+=y[i];return s/y.length;}
function cdStd(y){var m=cdMean(y),s=0;for(var i=0;i<y.length;i++)s+=(y[i]-m)*(y[i]-m);return Math.sqrt(s/(y.length||1));}
function cdSlope(y){var n=y.length;if(n<2)return 0;for(var i=0,sx=0,sy=0,sxx=0,sxy=0;i<n;i++){sx+=i;sy+=y[i];sxx+=i*i;sxy+=i*y[i];}var d=n*sxx-sx*sx;return d?(n*sxy-sx*sy)/d:0;}
function cdClassify(y){y=(y||[]).map(function(v){return +v||0;});var n=y.length;if(n<4)return 'New';var ys=cdSmooth(y,3),mean=cdMean(ys),slope=mean>0?cdSlope(ys):0,sp=mean>0?slope/mean*100:0;function win(k){if(n<2*k)return null;var r=cdMean(y.slice(-k)),pr=cdMean(y.slice(-2*k,-k));if(pr===0)return r===0?null:1;return (r-pr)/pr;}var ws=[win(4),win(8),win(13)].filter(function(w){return w!=null;});var nd=ws.filter(function(w){return w<-0.10;}).length,nu=ws.filter(function(w){return w>0.10;}).length;var k=Math.min(6,n),yr=ys.slice(-k),mr=cdMean(yr),rsp=mr>0?cdSlope(yr)/mr*100:0;var peak=Math.max.apply(null,ys),pi=ys.indexOf(peak),r3=cdMean(ys.slice(-3)),off=peak>0?(peak-r3)/peak:0,wsp=n-1-pi;var cv=cdMean(y)>0?cdStd(y)/cdMean(y):0;var t=Math.floor(n/3)||1,ft=cdMean(ys.slice(0,t)),lt=cdMean(ys.slice(-t));var emg=ft<=0.08*Math.max(lt,1e-9)&&lt>0;var vb=ft>1e-9?r3/ft:(r3>0?10:0);var nzf=cdMean(ys)>0?cdMean(ys.slice(-3))<0.2*cdMean(ys):false;var cpct=null,cz=null,cbh=false;if(n>=8){var rn=Math.max(1,Math.min(3,Math.floor(n/10))),bn=Math.max(4,Math.floor(n/3));if(n>=rn+bn){var rec=y.slice(-rn),base=y.slice(-(rn+bn),-rn),bm=cdMean(base),bs=cdStd(base),rm=cdMean(rec);cpct=bm>0?(rm-bm)/bm:null;cz=bs>0?(rm-bm)/bs:null;cbh=bm>=0.7*mean&&bm>0;}}if(cbh&&!nzf&&mean>0&&((cpct!=null&&cpct<-0.50)||(cpct!=null&&cpct<-0.30&&cz!=null&&cz<-2.5)))return 'Crashing';if(nzf)return 'Crashed';if(emg&&off<0.35&&wsp<=4)return 'New';if(sp<-1.0&&nd>=2)return 'Losing';if(off>=0.40&&rsp<2&&(vb<0.75||(vb<0.95&&sp<0)))return 'Losing';if(sp>1.0&&rsp>-1&&off<0.30&&nu>=1)return 'Winning';if(cv>=0.45&&Math.abs(sp)<1.5)return 'Volatile';return 'Healthy';}
var CRMETRIC={spend:{l:'Spend'},ctr:{l:'CTR'},roas:{l:'ROAS'},thumb:{l:'Thumbstop'},hold:{l:'Hold'},ret:{l:'Video retention'}};
function crMetricSel(){var e=document.querySelector('#cr-metric');return e?e.value:'ret';}
function crCurve(vals,color){vals=(vals||[]).map(function(v){return +v||0;});var n=vals.length;if(n<2)return '<div class="cr-nodata">No data</div>';var mx=Math.max.apply(null,vals);if(mx<=0)mx=1;var W=200,H=52,c=color||BRAND,gid='g'+c.replace(/[^a-z0-9]/gi,'');var X=function(i){return i/(n-1)*W;},Y=function(v){return H-2-(v/mx)*(H-7);};var pts=vals.map(function(v,i){return X(i)+','+Y(v);});var line='M'+pts.join('L');var area=line+'L'+W+','+H+'L0,'+H+'Z';return '<svg viewBox="0 0 '+W+' '+H+'" preserveAspectRatio="none" width="100%" style="height:52px;display:block"><defs><linearGradient id="'+gid+'" x1="0" x2="0" y1="0" y2="1"><stop offset="0%" stop-color="'+c+'" stop-opacity="0.28"/><stop offset="100%" stop-color="'+c+'" stop-opacity="0.02"/></linearGradient></defs><path d="'+area+'" fill="url(#'+gid+')"/><path d="'+line+'" fill="none" stroke="'+c+'" stroke-width="2.25" stroke-linejoin="round" vector-effect="non-scaling-stroke"/></svg>';}
function buildDaily(ddata){var m={};(ddata&&ddata.rows||[]).forEach(function(r){var k=r.facebook_ads_ad_name;if(!k)return;if(!m[k])m[k]=[];m[k].push({d:String(r.facebook_ads_date),im:num(r.facebook_ads_impressions),sp:num(r.facebook_ads_spend),lc:num(r.facebook_ads_inline_link_clicks),ro:num(r.facebook_ads_purchase_roas_purchase),vp:num(r.facebook_ads_video_play_actions),tp:num(r.facebook_ads_video_thruplay_watched_actions)});});var out={};Object.keys(m).forEach(function(k){var rows=m[k].sort(function(a,b){return a.d<b.d?-1:1;});out[k]={spend:rows.map(function(x){return x.sp;}),ctr:rows.map(function(x){return x.im>0?x.lc/x.im*100:0;}),roas:rows.map(function(x){return x.ro;}),thumb:rows.map(function(x){return x.im>0?x.vp/x.im*100:0;}),hold:rows.map(function(x){return x.im>0?x.tp/x.im*100:0;})};});window._crDmap=out;}
function renderTrends(mk){mk=mk||crMetricSel();var els=document.querySelectorAll('#creatives .cr-trend');for(var i=0;i<els.length;i++){var ad=els[i].getAttribute('data-ad');if(mk==='ret'){var ret=window._crRet&&window._crRet[ad];els[i].innerHTML='<div class="cr-ret-lbl">Video retention</div>'+(ret?crCurve(ret):'<div class="cr-nodata">No video data</div>')+'<div class="cr-ret-x"><span>3s</span><span>25%</span><span>50%</span><span>75%</span><span>100%</span></div>';continue;}var dm=window._crDmap&&window._crDmap[ad];var series=dm?dm[mk]:null;if(!series||series.length<2){els[i].innerHTML='<div class="cr-ret-lbl">'+(CRMETRIC[mk]?CRMETRIC[mk].l:mk)+' · daily</div><div class="cr-nodata">Loading…</div>';continue;}var vd=cdClassify(series);var col=(vd==='Winning'?'#16a34a':(vd==='Losing'||vd==='Crashing'||vd==='Crashed'?'#dc2626':BRAND));els[i].innerHTML='<div class="cr-trend-head"><span class="cr-ret-lbl">'+CRMETRIC[mk].l+' · daily</span><span class="dtag d-'+vd.toLowerCase()+'">'+vd+'</span></div>'+crCurve(series,col);}}
var L_creatives=function(){var host=document.querySelector('#creatives');if(!host)return;renderGhostCards(host,8);(window._crM||fetchRetry('chart_creatives_metrics',null,2)).then(function(data){host.classList.remove('porter-skeleton');renderCreativeCardsV2(host,data);(window._crDaily||fetchRetry('chart_creatives_daily',null,2)).then(function(dd){buildDaily(dd);renderTrends();}).catch(function(){});(window._crT||fetchRetry('chart_creatives',null,3)).then(function(td){var tm={};(td.rows||[]).forEach(function(r){var k=r.facebook_ads_ad_name;if(k&&r.facebook_ads_image_asset)tm[k]=imgUrl(r.facebook_ads_image_asset);});fillThumbs(host,tm);}).catch(function(){});}).catch(function(){host.classList.remove('porter-skeleton');host.innerHTML='<div class="empty">No creative data for this range</div>';});};

